                    <h2 id="endpoints-GETapi-v1-products">List products for POS</h2>

<p>
</p>

<p>GET /api/v1/products</p>
<p>Schema products:</p>
<ul>
<li>id (uuid)</li>
<li>tenant_id (uuid)</li>
<li>category_id (uuid)</li>
<li>recipe_id (uuid, nullable)</li>
<li>sku (string 50)</li>
<li>barcode (string 50, nullable)</li>
<li>name (string 200)</li>
<li>slug (string 220)</li>
<li>description (text, nullable)</li>
<li>image (string, nullable)</li>
<li>base_price (decimal)</li>
<li>cost_price (decimal, nullable)</li>
<li>product_type (string: single, variant, combo)</li>
<li>track_stock (boolean)</li>
<li>inventory_item_id (uuid, nullable)</li>
<li>is_active (boolean)</li>
<li>is_featured (boolean)</li>
<li>show_in_pos (boolean)</li>
<li>show_in_menu (boolean)</li>
<li>allow_notes (boolean)</li>
<li>prep_time_minutes (int, nullable)</li>
<li>sort_order (int)</li>
<li>tags (json, nullable)</li>
<li>allergens (json, nullable)</li>
<li>nutritional_info (json, nullable)</li>
<li>created_at, updated_at, deleted_at</li>
</ul>

